mapper.insert:
/* 멘탈케어 진단 결과 저장 mtlcare.insertResult */
INSERT INTO TB_MTLCARE_RESULT (
      RESULT_ID
    , USER_ID
    , SCORE_JSON
    , RISK_LEVEL
    , RISK_COLOR
    , RISK_BG_COLOR
    , RISK_SUMMARY
    , CORE_AREAS_SUMMARY
    , CREATE_DT
) VALUES (
      #{resultId}
    , #{userId}
    , #{scoreJson}
    , #{riskLevel, jdbcType=VARCHAR}
    , #{riskColor, jdbcType=VARCHAR}
    , #{riskBgColor, jdbcType=VARCHAR}
    , #{riskSummary, jdbcType=VARCHAR}
    , #{coreAreasSummary, jdbcType=VARCHAR}
    , NOW()
)

/* 면담 리포트 저장 mtlcare.insertReport */
INSERT INTO TB_MTLCARE_REPORT (
      REPORT_ID
    , RESULT_ID
    , REQ_USER_ID
    , REQ_USER_NM
    , MGR_USER_ID
    , REQ_COMMENT
    , TMPL_ID
    , REPORT_HTML
    , STATUS
    , CREATE_DT
) VALUES (
      #{reportId}
    , #{resultId}
    , #{reqUserId}
    , #{reqUserNm, jdbcType=VARCHAR}
    , #{mgrUserId}
    , #{reqComment, jdbcType=VARCHAR}
    , #{tmplId, jdbcType=VARCHAR}
    , #{reportHtml, jdbcType=VARCHAR}
    , 'REQ'
    , NOW()
)

mapper.update:
/* 면담 리포트 확인 처리 mtlcare.updateReportConfirm */
UPDATE TB_MTLCARE_REPORT
SET STATUS = 'CONFIRMED'
  , CONFIRM_DT = NOW()
WHERE REPORT_ID = #{reportId}
